// This is a Server Component (no "use client" directive)
async function BlogPage() {
  const posts = await db.query(`
    SELECT id, title, excerpt, created_at
    FROM posts
    ORDER BY created_at DESC
    LIMIT 10
  `);

  return (
    <div>
      <h1>Latest Posts</h1>
      {posts.map(post => (
        <article key={post.id}>
          <h2>{post.title}</h2>
          <p>{post.excerpt}</p>
          <small>{post.created_at.toLocaleDateString()}</small>
        </article>
      ))}
    </div>
  );
}

"use client";

import { useState } from "react";

function LikeButton({ postId, initialLikes }) {
  const [likes, setLikes] = useState(initialLikes);
  const [liked, setLiked] = useState(false);

  async function handleLike() {
    const res = await fetch("/api/like", {
      method: "POST",
      body: JSON.stringify({ postId }),
    });
    const data = await res.json();
    setLikes(data.likes);
    setLiked(true);
  }

  return (
    <button onClick={handleLike} disabled={liked}>
      {liked ? `${likes} ❤️` : `${likes} 🤍`}
    </button>
  );
}

// Server Component (parent)
async function PostPage({ params }) {
  const post = await db.query("SELECT * FROM posts WHERE id = $1", [params.id]);
  const comments = await db.query("SELECT * FROM comments WHERE post_id = $1", [params.id]);

  return (
    <article>
      <h1>{post.title}</h1>
      <div>{post.content}</div>
      {/* Server Component renders Client Component */}
      <LikeButton postId={post.id} initialLikes={post.likes} />
      <CommentList initialComments={comments} postId={post.id} />
    </article>
  );
}

